export enum DisasterType {
  WILDFIRE = 'Wildfire',
  FLOOD = 'Flood',
  EARTHQUAKE = 'Earthquake',
  HURRICANE = 'Hurricane',
  NONE = 'None'
}

export enum RiskLevel {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export interface SatelliteReport {
  timestamp: string;
  detectedAnomalies: string[];
  disasterType: DisasterType;
  riskLevel: RiskLevel;
  confidence: number;
  summary: string;
}

export interface SocialInsight {
  postCount: number;
  sentimentScore: number; // -1 to 1
  trendingKeywords: string[];
  alertTriggered: boolean;
  rawTextAnalysis: string;
}

export interface CloudNode {
  id: string;
  provider: 'GCP' | 'AWS' | 'Azure';
  region: string;
  status: 'active' | 'standby' | 'failed';
  latency: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { SatelliteReport, SocialInsight, DisasterType, RiskLevel } from "../types";

const API_KEY = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey: API_KEY });

export async function analyzeSatelliteImage(base64Image: string): Promise<SatelliteReport> {
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { mimeType: "image/jpeg", data: base64Image } },
        { text: "Analyze this satellite imagery for any signs of natural disasters (floods, fires, storms). Provide a detailed technical assessment." }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          detectedAnomalies: { type: Type.ARRAY, items: { type: Type.STRING } },
          disasterType: { type: Type.STRING },
          riskLevel: { type: Type.STRING },
          confidence: { type: Type.NUMBER },
          summary: { type: Type.STRING }
        },
        required: ["detectedAnomalies", "disasterType", "riskLevel", "confidence", "summary"]
      }
    }
  });

  const rawJson = response.text || "{}";
  return JSON.parse(rawJson);
}

export async function analyzeSocialFeed(posts: string[]): Promise<SocialInsight> {
  const model = "gemini-3-flash-preview";
  const combinedText = posts.join("\n---\n");

  const response = await ai.models.generateContent({
    model,
    contents: `Analyze these social media posts for real-time disaster indicators. Identify sentiment and emergency signals:\n${combinedText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          postCount: { type: Type.INTEGER },
          sentimentScore: { type: Type.NUMBER },
          trendingKeywords: { type: Type.ARRAY, items: { type: Type.STRING } },
          alertTriggered: { type: Type.BOOLEAN },
          rawTextAnalysis: { type: Type.STRING }
        },
        required: ["postCount", "sentimentScore", "trendingKeywords", "alertTriggered", "rawTextAnalysis"]
      }
    }
  });

  const rawJson = response.text || "{}";
  return JSON.parse(rawJson);
}

