import React, { useState } from 'react';
import { analyzeSatelliteImage } from '../services/geminiService';
import { SatelliteReport, DisasterType, RiskLevel } from '../types';

const SatelliteAnalysis: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [report, setReport] = useState<SatelliteReport | null>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setImage(base64);
      };
      reader.readAsDataURL(file);
    }
  };

  const startAnalysis = async () => {
    if (!image) return;
    setIsAnalyzing(true);
    try {
      const base64Data = image.split(',')[1];
      const result = await analyzeSatelliteImage(base64Data);
      setReport(result);
    } catch (error) {
      console.error("Analysis failed:", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const demoImages = [
    { name: 'Western Ridge (Wildfire)', url: 'https://picsum.photos/id/10/800/400' },
    { name: 'Coastal Basin (Flooding)', url: 'https://picsum.photos/id/11/800/400' },
    { name: 'City Center (Normal)', url: 'https://picsum.photos/id/12/800/400' }
  ];

  return (
    <div className="grid grid-cols-12 gap-6 h-full">
      <div className="col-span-12 lg:col-span-7 space-y-6">
        <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-800">
          <h4 className="text-slate-100 font-semibold mb-4 flex items-center gap-2">
            <i className="fa-solid fa-camera-retro text-blue-500"></i>
            Active Satellite Capture
          </h4>

          <div className="relative aspect-video bg-slate-800 rounded-lg overflow-hidden border border-slate-700 flex items-center justify-center group">
            {image ? (
              <img src={image} className="w-full h-full object-cover" alt="Satellite capture" />
            ) : (
              <div className="text-center p-12">
                <i className="fa-solid fa-upload text-4xl text-slate-600 mb-4"></i>
                <p className="text-slate-400">Upload satellite imagery for AI assessment</p>
                <input 
                  type="file" 
                  onChange={handleFileUpload}
                  className="absolute inset-0 opacity-0 cursor-pointer"
                  accept="image/*"
                />
              </div>
            )}

            {image && (
              <button 
                onClick={() => setImage(null)}
                className="absolute top-4 right-4 bg-red-500/80 p-2 rounded-full hover:bg-red-500 transition-colors"
              >
                <i className="fa-solid fa-times"></i>
              </button>
            )}
          </div>

          <div className="mt-6 flex items-center justify-between">
            <div className="flex gap-2">
              <button 
                onClick={startAnalysis}
                disabled={!image || isAnalyzing}
                className="px-6 py-2 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 disabled:hover:bg-blue-600 rounded-lg font-bold flex items-center gap-2 transition-all"
              >
                {isAnalyzing ? (
                  <>
                    <i className="fa-solid fa-spinner animate-spin"></i>
                    Analyzing Multi-Spectral Data...
                  </>
                ) : (
                  <>
                    <i className="fa-solid fa-microchip"></i>
                    Initiate AI Scan
                  </>
                )}
              </button>
            </div>

            <p className="text-xs text-slate-500 italic">Targeting Sensor: Spectral-7 Multimodal (Gemini-3 Flash)</p>
          </div>
        </div>

        <div className="grid grid-cols-3 gap-4">
          {demoImages.map((demo, idx) => (
            <button 
              key={idx}
              onClick={() => {
                // Mock fetching the demo image
                setImage(demo.url);
              }}
              className="bg-slate-900/50 p-2 rounded-lg border border-slate-800 hover:border-slate-500 transition-all text-left overflow-hidden group"
            >
              <img src={demo.url} className="h-20 w-full object-cover rounded mb-2 grayscale group-hover:grayscale-0 transition-all" alt={demo.name} />
              <span className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">{demo.name}</span>
            </button>
          ))}
        </div>
      </div>

      <div className="col-span-12 lg:col-span-5">
        <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-800 h-full flex flex-col">
          <h4 className="text-slate-100 font-semibold mb-6 flex items-center gap-2">
            <i className="fa-solid fa-file-waveform text-green-500"></i>
            AI Detection Report
          </h4>

          {report ? (
            <div className="space-y-6 flex-1">
              <div className="flex items-center justify-between p-4 bg-slate-950 rounded-lg border border-slate-800">
                <div>
                  <p className="text-xs text-slate-500 uppercase font-bold">Risk Classification</p>
                  <p className={`text-xl font-bold ${
                    report.riskLevel === RiskLevel.CRITICAL ? 'text-red-500' : 
                    report.riskLevel === RiskLevel.HIGH ? 'text-orange-500' : 'text-blue-400'
                  }`}>
                    {report.disasterType}
                  </p>
                </div>
                <div className="text-right">
                  <p className="text-xs text-slate-500 uppercase font-bold">Confidence</p>
                  <p className="text-xl font-mono text-slate-200">{(report.confidence * 100).toFixed(1)}%</p>
                </div>
              </div>

              <div>
                <p className="text-xs text-slate-500 uppercase font-bold mb-2">Detected Anomalies</p>
                <div className="flex flex-wrap gap-2">
                  {report.detectedAnomalies.map((a, i) => (
                    <span key={i} className="bg-slate-800 border border-slate-700 px-3 py-1 rounded text-sm text-slate-300">
                      {a}
                    </span>
                  ))}
                </div>
              </div>

              <div>
                <p className="text-xs text-slate-500 uppercase font-bold mb-2">Technical Summary</p>
                <p className="text-sm text-slate-400 leading-relaxed bg-slate-950/50 p-4 rounded-lg border border-slate-800/50 italic">
                  "{report.summary}"
                </p>
              </div>

              <div className="mt-auto pt-6 border-t border-slate-800">
                <button className="w-full py-3 bg-red-600 hover:bg-red-500 text-white rounded-lg font-bold flex items-center justify-center gap-2 transition-all">
                  <i className="fa-solid fa-triangle-exclamation"></i>
                  Escalate to Emergency Response
                </button>
              </div>
            </div>
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center text-center opacity-50">
              <i className="fa-solid fa-robot text-6xl mb-4 text-slate-700"></i>
              <p className="text-slate-500 max-w-[200px]">Waiting for image scan to generate technical intelligence...</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default SatelliteAnalysis;

import React, { useState } from 'react';
import { analyzeSocialFeed } from '../services/geminiService';
import { SocialInsight } from '../types';

const SocialMonitor: React.FC = () => {
  const [inputText, setInputText] = useState("");
  const [insight, setInsight] = useState<SocialInsight | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const mockPosts = [
    "Hearing loud sirens near downtown, smells like smoke? #Emergency",
    "Flooding on 5th street is getting worse, cars are stuck! Help!",
    "Stay safe everyone, the wind is picking up heavily. Power just went out.",
    "Anyone know why there are helicopters circling the residential zone?",
    "Massive traffic jam near the bridge, looks like some sort of disaster response."
  ];

  const handleAnalyze = async (customPosts?: string[]) => {
    setIsLoading(true);
    try {
      const postsToAnalyze = customPosts || (inputText ? [inputText] : mockPosts);
      const result = await analyzeSocialFeed(postsToAnalyze);
      setInsight(result);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="grid grid-cols-12 gap-6 h-full">
      <div className="col-span-12 lg:col-span-7 space-y-6">
        <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-800">
          <h4 className="text-slate-100 font-semibold mb-6 flex items-center gap-2">
            <i className="fa-solid fa-bullhorn text-amber-500"></i>
            Real-Time Social Stream Analysis
