          <div className="space-y-4 mb-6">
            <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">Active Stream Feed</p>
            <div className="bg-slate-950 rounded-lg border border-slate-800 divide-y divide-slate-800 overflow-hidden h-[300px] overflow-y-auto">
              {mockPosts.map((post, i) => (
                <div key={i} className="p-4 flex gap-4 hover:bg-slate-900 transition-colors">
                  <div className="w-8 h-8 rounded-full bg-slate-800 flex items-center justify-center text-slate-400">
                    <i className="fa-solid fa-user text-xs"></i>
                  </div>
                  <div>
                    <div className="flex gap-2 items-baseline mb-1">
                      <span className="text-xs font-bold text-slate-200">Anon_User_{i+102}</span>
                      <span className="text-[10px] text-slate-500">2m ago</span>
                    </div>
                    <p className="text-sm text-slate-400">{post}</p>
