        </div>
      </div>

      <div className="col-span-12 lg:col-span-5">
        <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-800 h-full">
           <h4 className="text-slate-100 font-semibold mb-6 flex items-center gap-2">
            <i className="fa-solid fa-magnifying-glass-chart text-purple-500"></i>
            Sentiment & Risk Intel
