import React, { useState, useEffect, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import SatelliteAnalysis from './components/SatelliteAnalysis';
import SocialMonitor from './components/SocialMonitor';
import InfrastructureMap from './components/InfrastructureMap';
import { generateLiveMonitoringIncident } from './services/geminiService';
import { Alert, RiskLevel } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [alerts, setAlerts] = useState<Alert[]>([
    { id: 'initial-1', time: '10:45 AM', type: 'Wildfire', location: 'California Sub-Sectors', severity: RiskLevel.CRITICAL, summary: 'Containment efforts breached by sudden wind shifts.', isLive: false },
    { id: 'initial-2', time: '09:22 AM', type: 'Storm Surge', location: 'Florida Coastal', severity: RiskLevel.MEDIUM, summary: 'Flood defense systems at 82% capacity.', isLive: false },
    { id: 'initial-3', time: '06:15 AM', type: 'Seismic Anomaly', location: 'Tokyo Ring', severity: RiskLevel.LOW, summary: 'Minor tremors detected, no structural damage reported.', isLive: false },
  ]);

  const [isScanning, setIsScanning] = useState(false);

  // Background poller for live incidents
  useEffect(() => {
    const fetchIncident = async () => {
      setIsScanning(true);
      try {
        const newIncident = await generateLiveMonitoringIncident();
        setAlerts(prev => {
          // Keep history to 8 items, de-live-ify the rest
          const updatedPrev = prev.map(a => ({ ...a, isLive: false }));
          return [newIncident, ...updatedPrev].slice(0, 8);
        });
      } catch (err) {
        console.error("Monitoring engine failure:", err);
      } finally {
        setIsScanning(false);
      }
    };

    // First fetch after 10 seconds, then every 45s
    const initialDelay = setTimeout(fetchIncident, 10000);
    const interval = setInterval(fetchIncident, 45000);

    return () => {
      clearTimeout(initialDelay);
      clearInterval(interval);
    };
  }, []);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard alerts={alerts} />;
      case 'satellite':
        return <SatelliteAnalysis />;
      case 'social':
        return <SocialMonitor />;
      case 'infrastructure':
        return <InfrastructureMap />;
      default:
        return <Dashboard alerts={alerts} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} alertCount={alerts.filter(a => a.isLive).length}>
      <div className="relative h-full">
        {isScanning && (
          <div className="absolute -top-4 right-0 flex items-center gap-2 text-[10px] font-bold text-blue-500 animate-pulse bg-blue-500/10 px-2 py-1 rounded border border-blue-500/20 z-50">
            <i className="fa-solid fa-satellite animate-spin"></i>
            ORBITAL SCAN IN PROGRESS...
          </div>
        )}
        {renderContent()}
      </div>
    </Layout>
  );
};

