import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import SatelliteAnalysis from './components/SatelliteAnalysis';
import SocialMonitor from './components/SocialMonitor';
import InfrastructureMap from './components/InfrastructureMap';
import { generateLiveMonitoringIncident, generateLiveSocialChatter, analyzeSocialFeed } from './services/geminiService';
import { Alert, RiskLevel, SocialPost, SocialInsight } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [alerts, setAlerts] = useState<Alert[]>([
    { id: 'initial-1', time: '10:45 AM', type: 'Wildfire', location: 'California Sub-Sectors', severity: RiskLevel.CRITICAL, summary: 'Containment efforts breached by sudden wind shifts.', isLive: false },
    { id: 'initial-2', time: '09:22 AM', type: 'Storm Surge', location: 'Florida Coastal', severity: RiskLevel.MEDIUM, summary: 'Flood defense systems at 82% capacity.', isLive: false },
    { id: 'initial-3', time: '06:15 AM', type: 'Seismic Anomaly', location: 'Tokyo Ring', severity: RiskLevel.LOW, summary: 'Minor tremors detected, no structural damage reported.', isLive: false },
  ]);

  const [socialPosts, setSocialPosts] = useState<SocialPost[]>([]);
  const [socialInsight, setSocialInsight] = useState<SocialInsight | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isAnalyzingSocial, setIsAnalyzingSocial] = useState(false);

  // Function to process and update social intelligence
  const updateSocialIntel = useCallback(async (context: string) => {
    setIsAnalyzingSocial(true);
    try {
      // 1. Generate new contextual chatter
      const newPosts = await generateLiveSocialChatter(context);

      setSocialPosts(prev => {
        const resetPrev = prev.map(p => ({ ...p, isNew: false, timeLabel: '5m ago' }));
        return [...newPosts, ...resetPrev].slice(0, 15);
      });

      // 2. Perform AI analysis on the updated feed
      const allText = [...newPosts.map(p => p.text), ...socialPosts.map(p => p.text)];
      const insight = await analyzeSocialFeed(allText.slice(0, 10));
      setSocialInsight(insight);
    } catch (err) {
      console.error("Social engine failure:", err);
    } finally {
      setIsAnalyzingSocial(false);
    }
  }, [socialPosts]);

  // Main background poller for incidents and social sync
  useEffect(() => {
    const mainLoop = async () => {
      setIsScanning(true);
      try {
        // Fetch new incident
        const newIncident = await generateLiveMonitoringIncident();
        setAlerts(prev => {
          const updatedPrev = prev.map(a => ({ ...a, isLive: false }));
          return [newIncident, ...updatedPrev].slice(0, 8);
        });

        // Immediately sync social chatter to the new incident
        await updateSocialIntel(`${newIncident.type} in ${newIncident.location}: ${newIncident.summary}`);
      } catch (err) {
        console.error("Global monitoring loop failure:", err);
      } finally {
        setIsScanning(false);
      }
    };

    // Initial sequence
    const initialDelay = setTimeout(mainLoop, 5000);
    const interval = setInterval(mainLoop, 60000); // Pulse every minute

    return () => {
      clearTimeout(initialDelay);
      clearInterval(interval);
    };
  }, []); // Run on mount

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard alerts={alerts} />;
      case 'satellite':
        return <SatelliteAnalysis />;
      case 'social':
        return (
          <SocialMonitor 
            posts={socialPosts} 
            insight={socialInsight} 
            isAnalyzing={isAnalyzingSocial} 
          />
        );
      case 'infrastructure':
        return <InfrastructureMap />;
      default:
        return <Dashboard alerts={alerts} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} alertCount={alerts.filter(a => a.isLive).length}>
      <div className="relative h-full">
        {isScanning && (
          <div className="absolute -top-4 right-0 flex items-center gap-2 text-[10px] font-bold text-blue-500 animate-pulse bg-blue-500/10 px-2 py-1 rounded border border-blue-500/20 z-50">
            <i className="fa-solid fa-satellite animate-spin"></i>
            GLOBAL SYNC IN PROGRESS...
          </div>
        )}
        {renderContent()}
      </div>
    </Layout>
  );
};

export default App;

