const API_KEY = process.env.API_KEY || '';

export async function analyzeSatelliteImage(base64Image: string): Promise<SatelliteReport> {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { mimeType: "image/jpeg", data: base64Image } },
        { text: "Analyze this satellite imagery for any signs of natural disasters. Provide a detailed technical assessment." }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          detectedAnomalies: { type: Type.ARRAY, items: { type: Type.STRING } },
          disasterType: { type: Type.STRING },
          riskLevel: { type: Type.STRING },
          confidence: { type: Type.NUMBER },
          summary: { type: Type.STRING }
        },
        required: ["detectedAnomalies", "disasterType", "riskLevel", "confidence", "summary"]
      }
    }
  });

  const rawJson = response.text || "{}";
  return JSON.parse(rawJson);
}

export async function analyzeSocialFeed(posts: string[]): Promise<SocialInsight> {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const model = "gemini-3-flash-preview";
  const combinedText = posts.join("\n---\n");

