            <svg viewBox="0 0 1000 500" className="w-full h-full p-8 opacity-80">
              {/* Simplified World Outline Background */}
              <rect width="1000" height="500" fill="transparent" />
              <path 
                d="M0,250 Q250,0 500,250 T1000,250 T500,500 T0,250" 
                fill="none" 
                stroke="#1e293b" 
                strokeWidth="1" 
                strokeDasharray="10,5"
