import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import SatelliteAnalysis from './components/SatelliteAnalysis';
import SocialMonitor from './components/SocialMonitor';
import GlobeView from './components/GlobeView';
import { generateLiveMonitoringIncident, generateLiveSocialChatter, analyzeSocialFeed, generatePredictions } from './services/geminiService';
import { Alert, RiskLevel, SocialPost, SocialInsight } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [alerts, setAlerts] = useState<Alert[]>([
    { id: 'initial-1', time: '10:45 AM', type: 'Wildfire', location: 'California Sub-Sectors', severity: RiskLevel.CRITICAL, summary: 'Containment efforts breached.', isLive: false, coordinates: { lat: 37.77, lng: -122.41 } },
    { id: 'initial-2', time: '09:22 AM', type: 'Storm Surge', location: 'Florida Coastal', severity: RiskLevel.MEDIUM, summary: 'Flood defense systems at 82% capacity.', isLive: false, coordinates: { lat: 25.76, lng: -80.19 } },
  ]);

  const [socialPosts, setSocialPosts] = useState<SocialPost[]>([]);
  const [socialInsight, setSocialInsight] = useState<SocialInsight | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isAnalyzingSocial, setIsAnalyzingSocial] = useState(false);

  const updateSocialIntel = useCallback(async (context: string) => {
    setIsAnalyzingSocial(true);
    try {
      const newPosts = await generateLiveSocialChatter(context);
      setSocialPosts(prev => [...newPosts, ...prev.map(p => ({ ...p, isNew: false }))].slice(0, 15));
      const insight = await analyzeSocialFeed(newPosts.map(p => p.text));
      setSocialInsight(insight);
    } catch (err) {
      console.error("Social engine failure:", err);
    } finally {
      setIsAnalyzingSocial(false);
    }
  }, []);

  const runPredictionLoop = useCallback(async () => {
    try {
      const preds = await generatePredictions();
      setAlerts(prev => {
        const withoutOldPreds = prev.filter(a => !a.isPrediction);
        return [...withoutOldPreds, ...preds];
      });
    } catch (err) {
      console.error("Prediction loop failure:", err);
    }
  }, []);

  useEffect(() => {
    const mainLoop = async () => {
      setIsScanning(true);
      try {
        const newIncident = await generateLiveMonitoringIncident();
        setAlerts(prev => [newIncident, ...prev.map(a => ({ ...a, isLive: false }))].slice(0, 15));
        await updateSocialIntel(`${newIncident.type} in ${newIncident.location}: ${newIncident.summary}`);
        await runPredictionLoop();
      } catch (err) {
        console.error("Global monitoring loop failure:", err);
      } finally {
        setIsScanning(false);
      }
    };

    const initialDelay = setTimeout(mainLoop, 2000);
    const interval = setInterval(mainLoop, 60000);

    return () => {
      clearTimeout(initialDelay);
      clearInterval(interval);
    };
  }, [updateSocialIntel, runPredictionLoop]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard alerts={alerts} />;
      case 'satellite': return <SatelliteAnalysis />;
      case 'social': return <SocialMonitor posts={socialPosts} insight={socialInsight} isAnalyzing={isAnalyzingSocial} />;
      case 'globe': return <GlobeView alerts={alerts} />;
      default: return <Dashboard alerts={alerts} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} alertCount={alerts.filter(a => a.isLive).length}>
      <div className="relative h-full">
        {isScanning && (
          <div className="absolute -top-4 right-0 flex items-center gap-2 text-[10px] font-bold text-blue-500 animate-pulse bg-blue-500/10 px-2 py-1 rounded border border-blue-500/20 z-50">
            <i className="fa-solid fa-satellite animate-spin"></i>
            PLANETARY DEFENSE SCAN...
          </div>
        )}
        {renderContent()}
      </div>
    </Layout>
  );
};

export default App;

