import { GoogleGenAI, Type } from "@google/genai";
import { SatelliteReport, SocialInsight, DisasterType, RiskLevel, Alert, AlertSource, SocialPost } from "../types";

// Removed global constant to follow guideline of using process.env.API_KEY directly in constructors

export async function analyzeSatelliteImage(base64Image: string): Promise<SatelliteReport> {
  // Use named parameter and direct process.env.API_KEY reference
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { mimeType: "image/jpeg", data: base64Image } },
        { text: "Analyze this satellite imagery for any signs of natural disasters. Provide a detailed technical assessment." }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          detectedAnomalies: { type: Type.ARRAY, items: { type: Type.STRING } },
          disasterType: { type: Type.STRING },
          riskLevel: { type: Type.STRING },
          confidence: { type: Type.NUMBER },
          summary: { type: Type.STRING }
        },
        required: ["detectedAnomalies", "disasterType", "riskLevel", "confidence", "summary"]
      }
    }
  });

  // response.text is a getter property
  const rawJson = response.text || "{}";
  return JSON.parse(rawJson);
}

export async function analyzeSocialFeed(posts: string[]): Promise<SocialInsight> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = "gemini-3-flash-preview";
  const combinedText = posts.join("\n---\n");

  const response = await ai.models.generateContent({
    model,
    // Fix: Include the combinedText in the prompt
    contents: `Analyze these social media posts for real-time disaster indicators: \n${combinedText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          postCount: { type: Type.INTEGER },
          sentimentScore: { type: Type.NUMBER },
          trendingKeywords: { type: Type.ARRAY, items: { type: Type.STRING } },
          alertTriggered: { type: Type.BOOLEAN },
          rawTextAnalysis: { type: Type.STRING }
        },
        required: ["postCount", "sentimentScore", "trendingKeywords", "alertTriggered", "rawTextAnalysis"]
      }
    }
  });

  return JSON.parse(response.text || "{}");
}

export async function generateLiveMonitoringIncident(): Promise<Alert> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: "Search for a major active natural disaster or emergency globally. Return JSON with type, location, severity, summary, and lat/lng coordinates.",
    config: {
      tools: [{googleSearch: {}}],
    }
  });

  const rawText = response.text || "";
  let data;
  try {
    const jsonMatch = rawText.match(/\{[\s\S]*\}/);
    data = JSON.parse(jsonMatch ? jsonMatch[0] : rawText);
  } catch (e) {
    data = { type: "Regional Emergency", location: "Pacific Rim", severity: "High", summary: "Seismic monitoring indicates activity.", lat: 35.67, lng: 139.65 };
  }

  const sources: AlertSource[] = (response.candidates?.[0]?.groundingMetadata?.groundingChunks || [])
    .map((chunk: any) => ({
      uri: chunk.web?.uri,
      title: chunk.web?.title || 'Verified Report'
    }))
    .filter((s: AlertSource) => s.uri);

  return {
    id: Math.random().toString(36).substr(2, 9),
    time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
    type: data.type,
    location: data.location,
    severity: data.severity as RiskLevel,
    summary: data.summary,
    isLive: true,
    coordinates: { lat: data.lat || 0, lng: data.lng || 0 },
    sources: sources.length > 0 ? sources : undefined
  };
}

