import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import SatelliteAnalysis from './components/SatelliteAnalysis';
import SocialMonitor from './components/SocialMonitor';
import GlobeView from './components/GlobeView';
import { generateLiveMonitoringIncident, generateLiveSocialChatter, analyzeSocialFeed, generatePredictions } from './services/geminiService';
import { Alert, RiskLevel, SocialPost, SocialInsight } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | undefined>(undefined);
  const [alerts, setAlerts] = useState<Alert[]>([
    { id: 'initial-1', time: '10:45 AM', type: 'Wildfire', location: 'California Sub-Sectors', severity: RiskLevel.CRITICAL, summary: 'Containment efforts breached.', isLive: false, coordinates: { lat: 37.77, lng: -122.41 } },
    { id: 'initial-2', time: '09:22 AM', type: 'Storm Surge', location: 'Florida Coastal', severity: RiskLevel.MEDIUM, summary: 'Flood defense systems at 82% capacity.', isLive: false, coordinates: { lat: 25.76, lng: -80.19 } },
  ]);

  const [socialPosts, setSocialPosts] = useState<SocialPost[]>([]);
  const [socialInsight, setSocialInsight] = useState<SocialInsight | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isAnalyzingSocial, setIsAnalyzingSocial] = useState(false);
  const [isThrottled, setIsThrottled] = useState(false);

  // Fetch current location on mount
  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setUserLocation({
            lat: position.coords.latitude,
            lng: position.coords.longitude
          });
        },
        (error) => console.warn("Location access denied. Using global monitoring defaults.", error)
      );
    }
  }, []);

  const updateSocialIntel = useCallback(async (context: string) => {
    setIsAnalyzingSocial(true);
    setIsThrottled(false);
    try {
      // Step 1: Generate chatter
      const newPosts = await generateLiveSocialChatter(context);
      setSocialPosts(prev => [...newPosts, ...prev.map(p => ({ ...p, isNew: false }))].slice(0, 15));

      // Step 2: SIGNIFICANT DELAY between calls to avoid 429 quota exhaustion
      await new Promise(resolve => setTimeout(resolve, 8000));

      // Step 3: Analyze feed
      const insight = await analyzeSocialFeed(newPosts.map(p => p.text));
      setSocialInsight(insight);
    } catch (err: any) {
      console.error("Social engine failure:", err);
      if (err?.message?.includes('429') || err?.status === 429) {
        setIsThrottled(true);
      }
    } finally {
      setIsAnalyzingSocial(false);
    }
  }, []);

  const runPredictionLoop = useCallback(async () => {
    try {
      const preds = await generatePredictions();
      setAlerts(prev => {
        const withoutOldPreds = prev.filter(a => !a.isPrediction);
        return [...withoutOldPreds, ...preds];
      });
    } catch (err: any) {
      console.error("Prediction loop failure:", err);
    }
  }, []);

  useEffect(() => {
    const mainLoop = async () => {
      if (isScanning) return; 
      setIsScanning(true);

      try {
        // 1. Fetch live incident (Heavy call - Maps Grounding)
        const newIncident = await generateLiveMonitoringIncident(userLocation?.lat, userLocation?.lng);
        setAlerts(prev => [newIncident, ...prev.map(a => ({ ...a, isLive: false }))].slice(0, 15));

        // 2. LONG STAGGER (10s) before hitting social to prevent "stops working" issue
        await new Promise(resolve => setTimeout(resolve, 10000));

        // 3. Update social if we have a context
        await updateSocialIntel(`${newIncident.type} in ${newIncident.location}: ${newIncident.summary}`);

        // 4. ANOTHER STAGGER
        await new Promise(resolve => setTimeout(resolve, 8000));

        // 5. Run predictions (Optional/Can fail independently)
        await runPredictionLoop();
      } catch (err) {
        console.error("Global monitoring loop failure:", err);
      } finally {
        setIsScanning(false);
      }
    };

    const initialDelay = setTimeout(mainLoop, 2000);
    const interval = setInterval(mainLoop, 150000); // 2.5 minutes interval for free tier sustainability

    return () => {
      clearTimeout(initialDelay);
      clearInterval(interval);
    };
  }, [updateSocialIntel, runPredictionLoop, userLocation]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard alerts={alerts} />;
      case 'satellite': return <SatelliteAnalysis />;
      case 'social': return <SocialMonitor posts={socialPosts} insight={socialInsight} isAnalyzing={isAnalyzingSocial} isThrottled={isThrottled} />;
      case 'globe': return <GlobeView alerts={alerts} />;
      default: return <Dashboard alerts={alerts} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} alertCount={alerts.filter(a => a.isLive).length}>
      <div className="relative h-full">
        {isScanning && (
          <div className="absolute -top-4 right-0 flex items-center gap-2 text-[10px] font-bold text-blue-500 animate-pulse bg-blue-500/10 px-3 py-1 rounded-full border border-blue-500/30 z-[2000]">
            <i className="fa-solid fa-satellite animate-spin text-[8px]"></i>
            ORBITAL RECON ACTIVE
          </div>
        )}
        {renderContent()}
      </div>
    </Layout>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { SatelliteReport, SocialInsight, DisasterType, RiskLevel, Alert, AlertSource, SocialPost } from "../types";

// Helper for exponential backoff retry logic
async function withRetry<T>(fn: () => Promise<T>, retries = 3, delay = 2000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    if (retries > 0 && (error?.status === 429 || error?.message?.includes('429') || error?.message?.includes('quota'))) {
      console.warn(`Quota exceeded. Retrying in ${delay}ms... (${retries} attempts left)`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

export async function analyzeSatelliteImage(base64Data: string, mimeType: string): Promise<SatelliteReport> {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = "gemini-3-flash-preview";

    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: base64Data } },
          { text: "Analyze this satellite imagery for any signs of natural disasters. Provide a detailed technical assessment. Identify specific anomalies like heat signatures, flood zones, or structural damage. Return strictly JSON." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            detectedAnomalies: { type: Type.ARRAY, items: { type: Type.STRING } },
            disasterType: { type: Type.STRING },
            riskLevel: { type: Type.STRING },
            confidence: { type: Type.NUMBER },
            summary: { type: Type.STRING }
          },
          required: ["detectedAnomalies", "disasterType", "riskLevel", "confidence", "summary"]
        }
      }
    });

    return JSON.parse(response.text || "{}");
  });
}

export async function analyzeSocialFeed(posts: string[]): Promise<SocialInsight> {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = "gemini-3-flash-preview";
    const combinedText = posts.join("\n---\n");

    const response = await ai.models.generateContent({
      model,
      contents: `Analyze these social media posts for real-time disaster indicators: \n${combinedText}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            postCount: { type: Type.INTEGER },
            sentimentScore: { type: Type.NUMBER },
            trendingKeywords: { type: Type.ARRAY, items: { type: Type.STRING } },
            alertTriggered: { type: Type.BOOLEAN },
            rawTextAnalysis: { type: Type.STRING }
          },
          required: ["postCount", "sentimentScore", "trendingKeywords", "alertTriggered", "rawTextAnalysis"]
        }
      }
    });

    return JSON.parse(response.text || "{}");
  });
}

export async function generateLiveMonitoringIncident(userLat?: number, userLng?: number): Promise<Alert> {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = "gemini-3-flash-preview"; 

    // Removed googleMaps to avoid API usage/quota issues
    const tools: any[] = [{ googleSearch: {} }];
    const config: any = { tools };

    const response = await ai.models.generateContent({
      model,
      contents: `Search for a major active natural disaster or emergency globally. Prioritize recent events near ${userLat}, ${userLng} if provided. Return a concise report starting with 'Type:', 'Location:', 'Severity:', 'Summary:', and 'Coords:' (in Lat,Lng format).`,
      config,
    });

    const text = response.text || "";
    const latMatch = text.match(/Lat:?\s*([-+]?\d*\.?\d+)/i);
    const lngMatch = text.match(/Lng:?\s*([-+]?\d*\.?\d+)/i);
    const typeMatch = text.match(/Type:?\s*([^\n,.]+)/i);
    const locMatch = text.match(/Location:?\s*([^\n,.]+)/i);

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources: AlertSource[] = chunks.map((chunk: any) => {
      if (chunk.web) {
        return { uri: chunk.web.uri, title: chunk.web.title || 'Web Intelligence' };
      }
      return null;
    }).filter(Boolean) as AlertSource[];

    return {
      id: Math.random().toString(36).substr(2, 9),
      time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      type: typeMatch ? typeMatch[1].trim() : "Regional Event",
      location: locMatch ? locMatch[1].trim() : "Global Monitoring Sector",
      severity: text.toLowerCase().includes('critical') ? RiskLevel.CRITICAL : RiskLevel.HIGH,
      summary: text.split('Summary:')[1]?.trim().split('Coords:')[0] || text.substring(0, 300),
      isLive: true,
      coordinates: { 
        lat: latMatch ? parseFloat(latMatch[1]) : (userLat || 0), 
        lng: lngMatch ? parseFloat(lngMatch[1]) : (userLng || 0) 
      },
      sources: sources.length > 0 ? sources : undefined
    };
  });
}

export async function generatePredictions(): Promise<Alert[]> {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = "gemini-3-flash-preview";

    const response = await ai.models.generateContent({
      model,
      contents: "Based on global climate and geological data, predict 3 locations where a disaster is likely to hit in the next 72 hours. Return as a JSON array of objects with fields: type, location, severity, summary, lat, lng.",
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING },
              location: { type: Type.STRING },
              severity: { type: Type.STRING },
              summary: { type: Type.STRING },
              lat: { type: Type.NUMBER },
              lng: { type: Type.NUMBER }
            },
            required: ["type", "location", "severity", "summary", "lat", "lng"]
          }
        }
      }
    });

    const rawData = JSON.parse(response.text || "[]");
    return rawData.map((d: any) => ({
      id: 'pred-' + Math.random().toString(36).substr(2, 9),
      time: 'PREDICTED',
      type: d.type,
      location: d.location,
      severity: d.severity as RiskLevel,
      summary: d.summary,
      isLive: false,
      isPrediction: true,
      coordinates: { lat: d.lat, lng: d.lng }
    }));
  });
}

export async function generateLiveSocialChatter(alertContext: string): Promise<SocialPost[]> {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = "gemini-3-flash-preview";

    const response = await ai.models.generateContent({
      model,
      contents: `Generate 5 realistic social media posts reacting to: "${alertContext}". Return JSON.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
