import React, { useState, useRef, useEffect } from 'react';
import { Alert, RiskLevel } from '../types';

interface GlobeViewProps {
  alerts: Alert[];
}

type MapStyle = 'tactical' | 'colored' | 'orbital';

const GlobeView: React.FC<GlobeViewProps> = ({ alerts }) => {
  const [selectedAlert, setSelectedAlert] = useState<Alert | null>(null);
  const [mapStyle, setMapStyle] = useState<MapStyle>('tactical');

  // Viewport State
  const [transform, setTransform] = useState({ x: 0, y: 0, k: 1 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  // Static High-Res World Map Image Assets (Styles)
  const mapAssets = {
    tactical: 'https://upload.wikimedia.org/wikipedia/commons/e/ea/Equirectangular-projection.jpg', // Using equirectangular as base
    colored: 'https://upload.wikimedia.org/wikipedia/commons/b/b3/World-map-2004-cia-factbook.jpg',
    orbital: 'https://upload.wikimedia.org/wikipedia/commons/8/83/Equirectangular_projection_SW.jpg'
  };

  // Mercator-ish Projection Mapping (0-100% based on Equirectangular Projection)
  const getPosition = (lat: number, lng: number) => {
    // longitude: -180 to 180 maps to 0% to 100%
    const x = ((lng + 180) / 360) * 100;
    // latitude: 90 to -90 maps to 0% to 100%
    const y = ((90 - lat) / 180) * 100;
    return { x, y };
  };

  const handleWheel = (e: React.WheelEvent) => {
    const delta = e.deltaY > 0 ? 0.9 : 1.1;
    setTransform(prev => ({
      ...prev,
      k: Math.min(Math.max(prev.k * delta, 1), 8)
    }));
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setDragStart({ x: e.clientX - transform.x, y: e.clientY - transform.y });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    setTransform(prev => ({
      ...prev,
      x: e.clientX - dragStart.x,
      y: e.clientY - dragStart.y
    }));
  };

  const handleMouseUp = () => setIsDragging(false);

  const activeAlerts = alerts.filter(a => !a.isPrediction);
  const predictedAlerts = alerts.filter(a => a.isPrediction);

  return (
    <div className="flex flex-col h-full space-y-6 min-h-0">
      <div className="grid grid-cols-12 gap-6 flex-1 min-h-0">
        {/* Main Map Container */}
        <div className="col-span-12 lg:col-span-9 bg-slate-900/50 rounded-xl border border-slate-800 relative overflow-hidden flex flex-col shadow-2xl">

          {/* HUD Overlay Top */}
          <div className="absolute top-0 left-0 right-0 p-6 flex justify-between items-start bg-gradient-to-b from-slate-950/90 to-transparent z-[50] pointer-events-none">
            <div className="space-y-2 pointer-events-auto">
              <h4 className="text-slate-100 font-semibold flex items-center gap-2 bg-slate-950/80 px-4 py-2 rounded-lg border border-slate-800 backdrop-blur-md shadow-lg">
                <i className="fa-solid fa-satellite-dish text-blue-500 animate-pulse"></i>
                Static Recon Interface
              </h4>
              <div className="flex gap-2">
                {(['tactical', 'colored', 'orbital'] as MapStyle[]).map((style) => (
                  <button
                    key={style}
                    onClick={() => setMapStyle(style)}
                    className={`px-3 py-1 rounded text-[10px] font-bold uppercase tracking-wider transition-all border ${
                      mapStyle === style 
                        ? 'bg-blue-600 border-blue-400 text-white shadow-lg shadow-blue-500/20' 
                        : 'bg-slate-900/80 border-slate-700 text-slate-400 hover:text-white hover:bg-slate-800'
                    }`}
                  >
                    {style}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex flex-col gap-2 items-end pointer-events-auto">
              <div className="flex gap-4 bg-slate-950/80 px-4 py-2 rounded-lg border border-slate-800 backdrop-blur-md shadow-lg">
                <div className="flex items-center gap-2 text-[10px] font-bold text-slate-300 uppercase tracking-widest">
                  <span className="w-2 h-2 bg-red-500 rounded-full"></span> Active
                </div>
                <div className="flex items-center gap-2 text-[10px] font-bold text-slate-300 uppercase tracking-widest">
                  <span className="w-2 h-2 bg-amber-500 rounded-full animate-pulse"></span> Forecast
                </div>
              </div>
            </div>
          </div>

          {/* Interactive Image-Based Map Viewer */}
          <div 
            ref={containerRef}
            className="flex-1 map-container overflow-hidden relative bg-slate-950"
            onWheel={handleWheel}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseUp}
          >
            <div 
              style={{
                transform: `translate(${transform.x}px, ${transform.y}px) scale(${transform.k})`,
                transition: isDragging ? 'none' : 'transform 0.2s ease-out',
                width: '100%',
                height: '100%',
                position: 'relative'
              }}
            >
              {/* The Static Map Texture */}
              <img 
                src={mapAssets[mapStyle]} 
                className={`w-full h-full object-cover select-none ${mapStyle === 'tactical' ? 'brightness-50 contrast-125 grayscale hue-rotate-180' : ''}`}
                alt="Static Map Texture"
              />

              {/* Marker Layer (SVG overlay to maintain sharpness) */}
              <svg className="absolute inset-0 w-full h-full overflow-visible pointer-events-none">
                {alerts.map((alert) => {
                  const { x, y } = getPosition(alert.coordinates.lat, alert.coordinates.lng);
                  const isPred = alert.isPrediction;
                  const color = isPred ? '#f59e0b' : '#ef4444';

                  return (
                    <g key={alert.id} className="cursor-pointer pointer-events-auto" onClick={() => setSelectedAlert(alert)}>
                      {/* Pulse Effect */}
                      <circle 
                        cx={`${x}%`} 
                        cy={`${y}%`} 
                        r={12 / transform.k} 
                        fill={color} 
                        fillOpacity="0.2"
                        className="animate-ping"
                      />
                      {/* Core Dot */}
                      <circle 
                        cx={`${x}%`} 
                        cy={`${y}%`} 
                        r={4 / transform.k} 
                        fill={color} 
                        stroke="white" 
                        strokeWidth={1 / transform.k}
                        className="shadow-xl"
                      />
                    </g>
                  );
                })}
              </svg>
            </div>
          </div>

          {/* Briefing Panel */}
          <div className="h-56 bg-slate-950/95 border-t border-slate-800 z-[100] p-6 relative backdrop-blur-xl">
            {selectedAlert ? (
              <div className="flex gap-8 items-start h-full animate-in fade-in slide-in-from-bottom-4 duration-500">
