                      {selectedAlert.isPrediction ? 'PREDICTION' : 'LIVE ALERT'}
                    </span>
                    <h3 className="text-2xl font-black text-slate-100 truncate tracking-tight">{selectedAlert.type}</h3>
                    <span className="px-2 py-0.5 rounded bg-slate-800 text-[10px] font-mono text-slate-400 border border-slate-700">
                      {selectedAlert.severity}
                    </span>
                  </div>
                  <div className="flex items-center gap-4 mb-4">
                    <p className="text-sm font-bold text-blue-400 flex items-center gap-2">
                      <i className="fa-solid fa-location-dot"></i>
                      {selectedAlert.location}
                    </p>
                    <span className="text-slate-700">|</span>
                    <p className="text-[10px] text-slate-500 font-mono">
                      COORD: {selectedAlert.coordinates.lat.toFixed(2)}, {selectedAlert.coordinates.lng.toFixed(2)}
