// Helper for exponential backoff retry logic
async function withRetry<T>(fn: () => Promise<T>, retries = 2, delay = 5000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const isQuotaError = error?.status === 429 || error?.message?.includes('429') || error?.message?.includes('quota');

    if (retries > 0 && isQuotaError) {
      console.warn(`Quota exceeded. Retrying in ${delay}ms... (${retries} attempts left)`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }

    // Pass the error through if we're out of retries or it's not a quota issue
    throw error;
  }
}

