import React, { useState, useEffect, useCallback, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import SatelliteAnalysis from './components/SatelliteAnalysis';
import SocialMonitor from './components/SocialMonitor';
import GlobeView from './components/GlobeView';
import LogisticsHub from './components/LogisticsHub';
import TimeMachine from './components/TimeMachine';
import { generateLiveMonitoringIncident, generateLiveSocialChatter, generatePredictions } from './services/geminiService';
import { Alert, SocialPost, SocialInsight } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | undefined>(undefined);
  // Start with empty alerts to ensure no auto-requests happen in sub-components
  const [alerts, setAlerts] = useState<Alert[]>([]);

  const [socialPosts, setSocialPosts] = useState<SocialPost[]>([]);
  const [socialInsight, setSocialInsight] = useState<SocialInsight | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isAnalyzingSocial, setIsAnalyzingSocial] = useState(false);
  const [isThrottled, setIsThrottled] = useState(false);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((pos) => setUserLocation({lat: pos.coords.latitude, lng: pos.coords.longitude}));
    }
  }, []);

  const triggerSystemSync = useCallback(async () => {
    if (isScanning) return; 
    setIsScanning(true);
    setIsThrottled(false);
    try {
      // Manual trigger for main disaster discovery
      const newIncident = await generateLiveMonitoringIncident(userLocation?.lat, userLocation?.lng);
      setAlerts(prev => [newIncident, ...prev.filter(a => !a.isPrediction)].slice(0, 15));

      // Secondary data flows only triggered after primary incident is found
      await generateLiveSocialChatter(newIncident.summary).then(setSocialPosts);
      await generatePredictions().then(p => setAlerts(prev => [...prev, ...p]));
    } catch (err: any) {
      if (err?.status === 429) setIsThrottled(true);
      console.error("Sync failed:", err);
    } finally {
      setIsScanning(false);
    }
  }, [userLocation, isScanning]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard alerts={alerts} />;
      case 'satellite': return <SatelliteAnalysis />;
      case 'social': return <SocialMonitor posts={socialPosts} insight={socialInsight} isAnalyzing={isAnalyzingSocial} isThrottled={isThrottled} />;
      case 'globe': return <GlobeView alerts={alerts} />;
      case 'response': return <LogisticsHub alerts={alerts.filter(a => !a.isPrediction)} />;
      case 'archives': return <TimeMachine />;
      default: return <Dashboard alerts={alerts} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} alertCount={alerts.filter(a => a.isLive).length} onSync={triggerSystemSync} isSyncing={isScanning} isThrottled={isThrottled}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { analyzeSatelliteImage } from '../services/geminiService';
import { SatelliteReport, RiskLevel } from '../types';

const SatelliteAnalysis: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isFetchingDemo, setIsFetchingDemo] = useState(false);
  const [report, setReport] = useState<SatelliteReport | null>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setImage(base64);
        setReport(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleDemoClick = async (url: string) => {
    setIsFetchingDemo(true);
    setReport(null);
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setIsFetchingDemo(false);
      };
      reader.readAsDataURL(blob);
    } catch (error) {
      console.error("Failed to fetch demo image:", error);
      setIsFetchingDemo(false);
    }
  };

  const startAnalysis = async () => {
    if (!image || isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const parts = image.split(',');
      const mimeType = parts[0].match(/:(.*?);/)?.[1] || 'image/jpeg';
      const base64Data = parts[1];

      const result = await analyzeSatelliteImage(base64Data, mimeType);
      setReport(result);
    } catch (error) {
      console.error("Analysis failed:", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  // Improved demo image IDs for topographical/satellite-like views
  const demoImages = [
    { name: 'Canyon Delta (Seismic)', url: 'https://picsum.photos/id/1016/800/400' },
    { name: 'Forest Grid (Thermal)', url: 'https://picsum.photos/id/1021/800/400' },
    { name: 'Basin Surge (Flooding)', url: 'https://picsum.photos/id/1015/800/400' }
  ];

  return (
    <div className="grid grid-cols-12 gap-6 h-full">
      <div className="col-span-12 lg:col-span-7 space-y-6">
        <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-800">
          <h4 className="text-slate-100 font-semibold mb-4 flex items-center gap-2">
            <i className="fa-solid fa-camera-retro text-blue-500"></i>
            Active Satellite Capture
          </h4>

          <div className="relative aspect-video bg-slate-950 rounded-lg overflow-hidden border border-slate-700 flex items-center justify-center group">
            {isFetchingDemo ? (
              <div className="text-center">
                <i className="fa-solid fa-cloud-arrow-down text-4xl text-blue-500 animate-bounce mb-4"></i>
                <p className="text-slate-400 font-mono text-xs">DOWNLOADING HIGH-RES IMAGERY...</p>
              </div>
            ) : image ? (
              <img src={image} className="w-full h-full object-cover" alt="Satellite capture" />
            ) : (
              <div className="text-center p-12">
                <i className="fa-solid fa-upload text-4xl text-slate-800 mb-4"></i>
                <p className="text-slate-500 text-sm mb-4">UPLINK SPECTRAL DATA</p>
                <div className="relative">
                  <button className="bg-slate-800 px-4 py-2 rounded border border-slate-700 text-xs font-bold hover:bg-slate-700 transition-all">Browse Files</button>
                  <input 
                    type="file" 
                    onChange={handleFileUpload}
                    className="absolute inset-0 opacity-0 cursor-pointer"
                    accept="image/*"
                  />
                </div>
              </div>
            )}

            {image && !isFetchingDemo && (
              <button 
                onClick={() => { setImage(null); setReport(null); }}
                className="absolute top-4 right-4 bg-red-500/80 p-2 rounded-full hover:bg-red-500 transition-colors z-10"
              >
                <i className="fa-solid fa-times"></i>
              </button>
            )}
          </div>

          <div className="mt-6 flex items-center justify-between">
            <div className="flex gap-2">
              <button 
                onClick={startAnalysis}
                disabled={!image || isAnalyzing || isFetchingDemo}
                className={`px-6 py-2 rounded-lg font-bold flex items-center gap-2 transition-all border ${
                  isAnalyzing 
                  ? 'bg-blue-600/10 border-blue-500/30 text-blue-400' 
                  : 'bg-blue-600 hover:bg-blue-500 border-blue-500 text-white'
                } disabled:opacity-30 disabled:cursor-not-allowed`}
              >
                {isAnalyzing ? (
                  <>
                    <i className="fa-solid fa-spinner animate-spin"></i>
                    SYNTHESIZING...
                  </>
                ) : (
                  <>
                    <i className="fa-solid fa-microchip"></i>
                    INITIATE AI SCAN
                  </>
                )}
              </button>
            </div>

            <p className="text-[10px] text-slate-500 font-mono">SENSOR: MULTIMODAL GEMINI-3</p>
          </div>
        </div>

        <div className="grid grid-cols-3 gap-4">
          {demoImages.map((demo, idx) => (
            <button 
              key={idx}
              disabled={isFetchingDemo || isAnalyzing}
              onClick={() => handleDemoClick(demo.url)}
              className="bg-slate-900/50 p-2 rounded-lg border border-slate-800 hover:border-blue-500/50 disabled:opacity-50 transition-all text-left overflow-hidden group"
