async function withRetry<T>(fn: () => Promise<T>, retries = 2, delay = 5000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const isQuotaError = error?.status === 429 || error?.message?.includes('429');
    if (retries > 0 && isQuotaError) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

export async function generatePreventionStrategy(type: string, location: string): Promise<PreventionStrategy> {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a pre-disaster prevention and mitigation blueprint for a ${type} in ${location}. Return JSON including blueprintName, checklist (array of {task, priority}), mitigationSteps (array), evacuationProtocols (array), and readinessScore (0-100).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            blueprintName: { type: Type.STRING },
            checklist: { 
              type: Type.ARRAY, 
              items: { 
                type: Type.OBJECT, 
                properties: { task: {type: Type.STRING}, priority: {type: Type.STRING} } 
              } 
            },
            mitigationSteps: { type: Type.ARRAY, items: { type: Type.STRING } },
            evacuationProtocols: { type: Type.ARRAY, items: { type: Type.STRING } },
            readinessScore: { type: Type.NUMBER }
          },
          required: ["blueprintName", "checklist", "mitigationSteps", "evacuationProtocols", "readinessScore"]
        }
      }
    });
    return JSON.parse(response.text || "{}");
  });
}

