async function withRetry<T>(fn: () => Promise<T>, retries = 2, delay = 5000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const isQuotaError = error?.status === 429 || error?.message?.includes('429');
    if (retries > 0 && isQuotaError) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

export async function analyzeSatelliteImage(base64Data: string, mimeType: string): Promise<SatelliteReport> {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType,
            },
          },
          {
            text: `Act as a senior orbital intelligence analyst. Analyze this high-resolution multi-spectral satellite imagery for emergency signatures.

            TASKS:
            1. Classify the primary disaster profile: Wildfire (thermal plumes/burn scars), Flood (increased turbidity/standing water), Earthquake (structural displacement/ruptures), Hurricane (concentric cloud formations/storm surge), or Normal/Baseline.
            2. Evaluate the Risk Level based on proximity to civilization and intensity: Low, Medium, High, or Critical.
            3. Detect specific spectral anomalies (e.g., 'Infrared spike at grid sector 4', 'Abnormal water retention in flood plains').
            4. Provide a technical, concise executive summary of the threat.

            Return ONLY a valid JSON object.`,
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            disasterType: { type: Type.STRING },
            riskLevel: { type: Type.STRING },
            confidence: { type: Type.NUMBER },
            detectedAnomalies: { type: Type.ARRAY, items: { type: Type.STRING } },
            summary: { type: Type.STRING },
          },
          required: ["disasterType", "riskLevel", "confidence", "detectedAnomalies", "summary"],
        },
      },
    });
    return JSON.parse(response.text || "{}");
  });
}

